  ('social-worker-moex-03072', 'social-worker', 'social-worker-moex-101-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '施用管理理論之原則是：「參考過去、適應現勢、體察未來」，下列何者非為其定律？', '["經驗律：指累積經驗，以因應時、空、人、物、事之異動或變化", "環境律：指觀察自然、文化、社會等環境影響因素，以視時、空、人、物、事之不同而靈活運用", "法治律：指凡事需以法令為主，不可違背", "趨勢律：指注意情勢而權變，不拘泥於一成不變"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:15+00:00", "source_pdf_sha1": "f25d69c4ae45", "answer_pdf_sha1": "beebb3921050", "source_family": "moex-gov-tw", "moex": {"exam_code": "101030", "c": "902", "s": "0803", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "101", "exam_name": "101年第一次專技醫師分試中醫師營養師心理師藥師醫事檢驗師護理師護士社會工作師考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
